// Some portions generated by Claude Code
package org.eclipse.rdf4j.query.algebra.evaluation.impl.evaluationsteps;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.common.order.StatementOrder;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryEvaluationException;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryBindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.TripleSource;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.QueryEvaluationContext;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

/**
 * Verifies that the statement-to-binding-set wrappers produced by {@link StatementPatternQueryEvaluationStep} forward
 * the advisory seek hint to the underlying ordered statement iteration, and that filter-wrapped patterns (which cannot
 * prove an empty lookahead) do not expose the capability.
 */
public class StatementPatternSeekForwardingTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI PREDICATE = VF.createIRI("http://example.com/p");

	private static final class RecordingSeekStatementIteration implements CloseableIteration<Statement> {

		private final Iterator<Statement> statements;
		private final List<Value> seekTargets = new ArrayList<>();

		private RecordingSeekStatementIteration(List<Statement> statements) {
			this.statements = statements.iterator();
		}

		@Override
		public boolean hasNext() {
			return statements.hasNext();
		}

		@Override
		public Statement next() {
			return statements.next();
		}

		@Override
		public void seek(Value minValue, boolean minInclusive, Value maxValue, boolean maxInclusive) {
			seekTargets.add(minValue);
		}

		@Override
		public boolean supportsSeek() {
			return true;
		}

		@Override
		public void close() {
		}
	}

	private static final class RecordingTripleSource implements TripleSource {

		private RecordingSeekStatementIteration lastOrderedIteration;

		private List<Statement> statements() {
			List<Statement> statements = new ArrayList<>();
			for (int i = 0; i < 5; i++) {
				statements.add(VF.createStatement(VF.createIRI("http://example.com/s" + i), PREDICATE,
						VF.createIRI("http://example.com/o" + i)));
			}
			return statements;
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
				Resource... contexts) throws QueryEvaluationException {
			return new RecordingSeekStatementIteration(statements());
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(StatementOrder statementOrder, Resource subj,
				IRI pred, Value obj, Resource... contexts) throws QueryEvaluationException {
			lastOrderedIteration = new RecordingSeekStatementIteration(statements());
			return lastOrderedIteration;
		}

		@Override
		public ValueFactory getValueFactory() {
			return VF;
		}
	}

	private static StatementPattern orderedPattern(String subjectVarName, String objectVarName) {
		StatementPattern pattern = new StatementPattern(new Var(subjectVarName),
				new Var("p", PREDICATE, true, true), new Var(objectVarName));
		pattern.setOrder(pattern.getSubjectVar());
		return pattern;
	}

	@Test
	public void forwardsSeekWithEmptyBindings() {
		RecordingTripleSource tripleSource = new RecordingTripleSource();
		StatementPatternQueryEvaluationStep step = new StatementPatternQueryEvaluationStep(orderedPattern("s", "o"),
				new QueryEvaluationContext.Minimal(null), tripleSource);

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertNotNull(iteration);
			assertTrue(iteration.supportsSeek());
			iteration.seek(VF.createIRI("http://example.com/s3"), true, null, true);
			assertNotNull(tripleSource.lastOrderedIteration);
			assertTrue(tripleSource.lastOrderedIteration.seekTargets
					.contains(VF.createIRI("http://example.com/s3")));
		}
	}

	@Test
	public void forwardsSeekWithNonEmptyBindings() {
		RecordingTripleSource tripleSource = new RecordingTripleSource();
		StatementPatternQueryEvaluationStep step = new StatementPatternQueryEvaluationStep(orderedPattern("s", "o"),
				new QueryEvaluationContext.Minimal(null), tripleSource);

		QueryBindingSet bindings = new QueryBindingSet();
		bindings.addBinding("unrelated", VF.createLiteral("x"));

		try (CloseableIteration<BindingSet> iteration = step.evaluate(bindings)) {
			assertNotNull(iteration);
			assertTrue(iteration.supportsSeek());
			iteration.seek(VF.createIRI("http://example.com/s3"), true, null, true);
			assertNotNull(tripleSource.lastOrderedIteration);
			assertTrue(tripleSource.lastOrderedIteration.seekTargets
					.contains(VF.createIRI("http://example.com/s3")));
		}
	}

	@Test
	public void sameVariablePatternDoesNotForward() {
		RecordingTripleSource tripleSource = new RecordingTripleSource();
		// ?s <p> ?s requires a filter wrapper with its own lookahead, which hides the seek capability
		StatementPatternQueryEvaluationStep step = new StatementPatternQueryEvaluationStep(orderedPattern("s", "s"),
				new QueryEvaluationContext.Minimal(null), tripleSource);

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertNotNull(iteration);
			assertFalse(iteration.supportsSeek());
			iteration.seek(VF.createIRI("http://example.com/s3"), true, null, true);
			assertNotNull(tripleSource.lastOrderedIteration);
			assertTrue(tripleSource.lastOrderedIteration.seekTargets.isEmpty());
		}
	}
}
